// ---------------------------------------------------------------------------
// CPU reference fixture validation — structural well-formedness
//
// These tests assert that every op's fixture entries are well-formed: they
// have `expected` values, `x` or (`a`,`b`) fields, and a consistent shape.
// The values themselves are reference material for when live XPU is available.
// ---------------------------------------------------------------------------

fn check_cpu_reference_fixtures(op_name: &str, expect_ab: bool, file: &FixtureFile) {
    let cases = fixtures_for(file, op_name);
    assert!(
        !cases.is_empty(),
        "no fixtures for op {op_name:?} — regenerate via scripts/regenerate_xpu_fixtures.py"
    );
    for (i, f) in cases.iter().enumerate() {
        let label = format!("{op_name}[{i}]");
        assert!(
            f.cascade_skip_live_xpu,
            "{label}: expected cascade_skip_live_xpu=true (no Intel XPU)"
        );
        let expected = f
            .expected
            .as_ref()
            .unwrap_or_else(|| panic!("{label}: missing `expected` field in fixture"));
        assert!(!expected.is_empty(), "{label}: expected values are empty");
        if expect_ab {
            assert!(f.a.is_some(), "{label}: missing `a` field");
            assert!(f.b.is_some(), "{label}: missing `b` field");
            assert_eq!(
                f.a.as_ref().unwrap().len(),
                expected.len(),
                "{label}: `a` length must match `expected`"
            );
        } else {
            assert!(f.x.is_some(), "{label}: missing `x` field");
        }
    }
}

