#[test]
fn cpu_reference_matmul_well_formed() {
    let file = load_fixtures();
    let cases = fixtures_for(&file, "xpu_matmul");
    assert!(!cases.is_empty(), "no xpu_matmul fixtures found");
    for (i, f) in cases.iter().enumerate() {
        let label = format!("xpu_matmul[{i}]");
        assert!(
            f.cascade_skip_live_xpu,
            "{label}: must be cascade_skip_live_xpu"
        );
        assert!(f.a_shape.is_some(), "{label}: missing a_shape");
        assert!(f.b_shape.is_some(), "{label}: missing b_shape");
        assert!(
            f.expected_shape.is_some(),
            "{label}: missing expected_shape"
        );
        assert!(f.expected.is_some(), "{label}: missing expected");
        let a_shape = f.a_shape.as_ref().unwrap();
        let b_shape = f.b_shape.as_ref().unwrap();
        assert_eq!(a_shape.len(), 2, "{label}: a must be 2-D");
        assert_eq!(b_shape.len(), 2, "{label}: b must be 2-D");
        assert_eq!(
            a_shape[1], b_shape[0],
            "{label}: a_shape[1] must equal b_shape[0] (inner dims)"
        );
    }
}

// ---------------------------------------------------------------------------
// Error-contract fixtures
// ---------------------------------------------------------------------------

/// The fixture asserts that xpu_add rejects a non-XPU operand with
/// DeviceMismatch or DeviceUnavailable. Verify fixture well-formedness and
/// assert ferrotorch's stub mode returns DeviceUnavailable (which satisfies
/// the "either" contract).
#[test]
fn xpu_add_rejects_non_xpu_input_contract() {
    let file = load_fixtures();
    let cases = fixtures_for(&file, "xpu_add_rejects_cpu_input");
    assert!(
        !cases.is_empty(),
        "fixture xpu_add_rejects_cpu_input not found"
    );

    let f = cases[0];
    let accepted_variants = f.expected_error_variants.as_deref().unwrap_or(&[]);
    // DeviceUnavailable and DeviceMismatch are both in the fixture's accepted list.
    assert!(
        accepted_variants
            .iter()
            .any(|v| v == "DeviceUnavailable" || v == "DeviceMismatch"),
        "fixture must accept DeviceUnavailable or DeviceMismatch"
    );
    // Verify XpuDevice::new fails (or panics) without hardware; use catch_unwind
    // because wgpu may panic internally on WSL2 when no Vulkan adapter exists.
    let device_result =
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| XpuDevice::new(0)));
    match device_result {
        Ok(Ok(_)) => {
            // Live device found; the DeviceMismatch path applies (not DeviceUnavailable).
            // cascade_skip: live-path test is deferred to #836.
            cascade_skip!(
                "live XPU device present; DeviceMismatch live-path deferred — crosslink bug #836"
            );
        }
        Ok(Err(FerrotorchError::DeviceUnavailable)) => {
            // Expected stub mode: DeviceUnavailable satisfies the fixture contract.
        }
        Ok(Err(_other)) => {
            // Other error (driver init failure) also satisfies "can't get a device".
        }
        Err(_panic) => {
            // wgpu panic on missing Vulkan adapter — also acceptable; no device.
        }
    }
}

/// `xpu_matmul` rejects 1-D inputs with `ShapeMismatch`. In stub mode the
/// error will be `DeviceUnavailable` before shape validation fires, but the
/// fixture documents the live-path contract.
///
/// Phase 4 (#1054): the previous body only asserted the fixture's
/// `expected_error_variant == "ShapeMismatch"`, never invoking
/// `xpu_matmul`. The strengthened version (a) keeps the fixture
/// well-formedness check (it documents the live-path contract a fixture
/// regeneration must preserve), (b) pins `xpu_matmul`'s signature with
/// a typed function-pointer reference so a contract drift fails to
/// type-check, and (c) cascade_skip's the live invocation to crosslink
/// bug #836 because we cannot construct an `XpuDevice` here. The
/// in-crate `xpu_matmul_rejects_non_2d_inputs` test in src/lib.rs
/// (line 704) covers the live-path assertion when wgpu hardware is
/// present.
#[test]
fn xpu_matmul_rejects_1d_input_contract() {
    let file = load_fixtures();
    let cases = fixtures_for(&file, "xpu_matmul_rejects_1d_input");
    assert!(
        !cases.is_empty(),
        "fixture xpu_matmul_rejects_1d_input not found"
    );

    let f = cases[0];
    assert_eq!(
        f.expected_error_variant.as_deref().unwrap_or(""),
        "ShapeMismatch",
        "fixture must document ShapeMismatch for 1-D matmul"
    );

    // Pin `xpu_matmul`'s signature — a drift (e.g. removing the device
    // parameter, or changing the result type) fails to type-check here.
    pin_binary_op_signature(xpu_matmul);

    // Live-path invocation requires an XpuDevice; cascade_skip with the
    // existing live-XPU follow-up. The src/ test
    // `xpu_matmul_rejects_non_2d_inputs` (lib.rs:704) exercises this
    // contract when wgpu hardware is present.
    let device_result =
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| XpuDevice::new(0)));
    if matches!(device_result, Ok(Ok(_))) {
        cascade_skip!(
            "xpu_matmul live-path 1-D rejection assertion deferred — \
             live XPU device present but skipped on this CI lane; the in-crate \
             test xpu_matmul_rejects_non_2d_inputs covers it. crosslink bug #836"
        );
    }
    cascade_skip!(
        "xpu_matmul live-path 1-D rejection assertion deferred — cannot \
         construct XpuDevice without hardware on this box; in-crate test \
         xpu_matmul_rejects_non_2d_inputs (lib.rs:704) is the live-path \
         coverage. crosslink bug #836; follow-up #1076 would unblock a \
         stub-mode runtime check via pub(crate) fn new_for_testing."
    );
}

